//! Bundled single-page chat UI for the Forge MVP.

pub const CHAT_HTML: &str = r##"<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Forge Unified</title>
<style>
:root{color-scheme:dark;--bg:#070708;--panel:#151518;--panel2:#1f1f24;--text:#f4f4f5;--muted:#a1a1aa;--border:rgba(255,255,255,.13);--accent:#d6a84f;--ok:#8fd18f;--bad:#f48a99;--blue:#8ab4f8;--mono:ui-monospace,SFMono-Regular,Menlo,Consolas,monospace}*{box-sizing:border-box}body{margin:0;background:#070708;color:var(--text);font:15px/1.5 system-ui,sans-serif}.app{display:grid;grid-template-columns:260px 1fr;height:100vh}.sidebar{border-right:1px solid var(--border);padding:1rem;background:#0d0d10;overflow:auto}main{display:grid;grid-template-rows:auto auto auto 1fr auto;min-width:0}.top{border-bottom:1px solid var(--border);padding:.9rem 1.2rem}.identity{border-bottom:1px solid var(--border);padding:.65rem 1.2rem;background:rgba(214,168,79,.10);color:var(--accent);font-family:var(--mono);font-size:.82rem}.proofbar{display:none;border-bottom:1px solid var(--border);padding:.8rem 1.2rem;background:#0b0b0d}.messages{overflow:auto;padding:1rem 2rem;display:flex;flex-direction:column;gap:.75rem}.message{max-width:960px;width:100%;align-self:center;border:1px solid var(--border);border-radius:18px;background:var(--panel);padding:.85rem;white-space:pre-wrap;overflow-wrap:anywhere}.message.user{background:#202025}.role{font-size:.72rem;color:var(--muted);text-transform:uppercase;letter-spacing:.08em;margin-bottom:.35rem}.tool{border:1px solid var(--border);border-radius:16px;margin-top:.55rem;padding:.7rem;background:#09090b}.tool.ok{border-color:rgba(143,209,143,.45)}.tool.err{border-color:rgba(244,138,153,.55)}.tool.live{border-color:rgba(214,168,79,.58);background:#11100d}.tool-head{display:flex;align-items:center;gap:.5rem;justify-content:space-between}.tool-title{font-weight:800}.tool-sub{margin-top:.25rem;color:var(--muted);font-size:.82rem}.badge{display:inline-block;border:1px solid var(--border);border-radius:999px;padding:.1rem .48rem;font:11px var(--mono);color:var(--muted)}.badge.ok{color:var(--ok);border-color:rgba(143,209,143,.45)}.badge.err{color:var(--bad);border-color:rgba(244,138,153,.55)}.badge.info{color:var(--blue)}.tool-result{margin-top:.45rem}.stage{display:inline-block;border:1px solid var(--border);border-radius:999px;padding:.1rem .45rem;margin:.15rem .25rem .15rem 0;font:11px var(--mono);color:var(--accent)}.rail{max-width:960px;width:100%;align-self:center;border:1px dashed rgba(214,168,79,.45);border-radius:14px;background:#0d0d10;padding:.65rem;font-family:var(--mono);font-size:.78rem}.rail strong,.catalog strong{color:var(--accent)}button{border:1px solid var(--border);border-radius:12px;padding:.55rem .75rem;background:#202025;color:var(--text)}button.primary{background:linear-gradient(180deg,#dfbd68,#bd8f35);color:#111;border:0;font-weight:700}.conv{display:block;width:100%;text-align:left;margin:.35rem 0}.conv.active{border-color:var(--accent)}textarea{width:100%;min-height:4rem;border-radius:14px;border:1px solid var(--border);background:#121216;color:var(--text);padding:.8rem}.composer{border-top:1px solid var(--border);padding:1rem 2rem;background:#0d0d10}.composer-inner{display:grid;grid-template-columns:1fr auto;gap:.75rem}.muted{color:var(--muted);font-size:.82rem}.mini{font-size:.78rem;color:var(--muted)}pre{overflow:auto;max-height:12rem;background:#050506;border:1px solid var(--border);border-radius:12px;padding:.6rem}.activity{position:fixed;right:1rem;top:1rem;border:1px solid var(--border);border-radius:14px;background:#101014;padding:.65rem}.catalog{position:fixed;right:1rem;top:4.8rem;width:330px;max-height:35vh;overflow:auto;border:1px solid var(--border);border-radius:14px;background:#101014;padding:.65rem;font-size:.78rem}.catalog .pill{display:inline-block;margin:.14rem;padding:.1rem .38rem;border:1px solid var(--border);border-radius:999px}.toast{position:fixed;right:1rem;bottom:1rem;display:none;border:1px solid var(--border);background:#101014;border-radius:14px;padding:.7rem}.toast.show{display:block}.proof-card{max-width:1180px;width:100%;align-self:center;border:1px solid rgba(214,168,79,.48);border-radius:18px;background:linear-gradient(180deg,rgba(214,168,79,.12),rgba(255,255,255,.03));padding:1rem}.proof-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:.6rem;margin:.75rem 0}.metric{border:1px solid var(--border);border-radius:14px;padding:.65rem;background:#0f0f12}.metric b{display:block;font-size:1.05rem}.final-answer{border:1px solid var(--border);border-radius:14px;padding:.75rem;background:#0b0b0d;max-height:24rem;overflow:auto}.file-list{display:flex;flex-wrap:wrap;gap:.35rem}.file-pill{border:1px solid var(--border);border-radius:999px;padding:.1rem .45rem;font:11px var(--mono);color:var(--blue)}body.proof-final .sidebar,body.proof-final .composer,body.proof-final .activity,body.proof-final .catalog{display:none}body.proof-final .app{grid-template-columns:1fr}body.proof-final main{grid-template-rows:auto auto auto 1fr}body.proof-final .proofbar{display:block}body.proof-final .messages{padding:1rem 1.5rem}body.proof-final .message{max-width:1180px}body.proof-final .message.user{display:none}body.proof-final details{display:none}body.proof-final .tool{margin-top:.35rem}body.proof-final .tool-sub{display:none}body.proof-final .rail{max-height:10rem;overflow:auto}
</style>
</head>
<body data-proof="live-browser-model-proof provider-model-visible opencode-codex-dark-ui opencode-tool-lifecycle-rail providerExecuted-visible opencode-provider-tool-catalog apply_patch-visible proof-digest-visible human-tool-label">
<div class="app">
<aside class="sidebar"><h1>Forge Unified</h1><div class="muted">OpenCode-style builder workspace.</div><button id="new" class="primary">New conversation</button><div class="muted"><span id="count">0</span> conversations</div><div id="list"></div></aside>
<main><div class="top"><strong id="title">No conversation selected</strong><div id="subtitle" class="muted">conversation id</div></div><div id="identity" class="identity" data-proof="provider-model-visible">provider: none · model: none · route: none</div><div id="proofbar" class="proofbar" data-proof="proof-final-summary final-answer-visible">Readable proof summary</div><section id="messages" class="messages"></section><div class="composer"><div class="composer-inner"><textarea id="input" disabled placeholder="Ask Forge to inspect, edit, or summarize this repo."></textarea><button id="send" class="primary" disabled>Send</button></div><div class="muted">Proof requires real model route, not local shortcut. Visible cards summarize actions first; technical JSON stays collapsed.</div></div></main>
</div>
<div class="activity" data-proof="main-chat-event-rail">Activity: files · commands · diagnostics · provider route</div><div id="catalog" class="catalog" data-proof="opencode-provider-tool-catalog"><strong>Available actions</strong><div class="muted">loading provider tools…</div></div><div id="toast" class="toast"></div>
<script>
const s={items:[],id:null,conv:null,busy:false,stream:null,tools:new Map(),rail:null};const $=id=>document.getElementById(id);const params=new URLSearchParams(location.search);const wanted=params.get('conversation');const proofMode=params.get('proof')||'';const proofFinal=proofMode==='final';if(proofFinal)document.body.classList.add('proof-final');
const LABELS={repo_info:'Inspect repo',file_list:'List files',file_glob:'Find files',file_search:'Search files',file_read:'Read file',file_write:'Write file',file_edit:'Edit file',file_delete:'Delete file',apply_patch:'Apply patch',propose_patch:'Propose patch',shell_command:'Run command',terminal_run:'Run terminal command',task:'Delegate subtask',todo_write:'Update plan',batch_parallel:'Run tools in parallel',web_fetch:'Fetch web page',web_search:'Search web',browser_proof:'Capture browser proof',vision_review:'Review screenshot',graph_build:'Build code graph',graph_query:'Query code graph',mode_switch:'Switch mode'};
function idv(v){return !v?'none':(typeof v==='string'?v:(v[0]||JSON.stringify(v)))}
function label(n){return LABELS[n]||String(n||'Tool').replace(/_/g,' ').replace(/\b\w/g,c=>c.toUpperCase())}
function toast(t){const e=$('toast');e.textContent=t;e.className='toast show';clearTimeout(toast.t);toast.t=setTimeout(()=>e.className='toast',3000)}
async function api(path,opt={}){const r=await fetch(path,{headers:{'content-type':'application/json'},...opt});const txt=await r.text();let d=null;try{d=txt?JSON.parse(txt):null}catch{d=txt}if(!r.ok)throw new Error(txt);return d}
function setIdent(conv,run){const p=idv(run?.provider||conv?.provider);const m=idv(run?.model||conv?.model);const route=p==='local'?'LOCAL SHORTCUT':'MODEL ROUTE';$('identity').textContent=`provider: ${p} · model: ${m} · route: ${route}`;$('identity').dataset.provider=p;$('identity').dataset.model=m}
async function loadCatalog(){const c=await api('/api/tools');const names=c.names||[];$('catalog').innerHTML=`<strong>Available actions</strong><div class="muted">${c.tool_count} provider-visible actions · apply patch supported</div><div>${names.map(n=>`<span class="pill" title="${n}" data-tool-name="${n}">${label(n)}</span>`).join('')}</div>`;$('catalog').dataset.toolCount=String(c.tool_count);$('catalog').dataset.applyPatch=String(names.includes('apply_patch'))}
async function load(select){s.items=await api('/api/conversations');s.items.sort((a,b)=>String(b.updated_at||'').localeCompare(String(a.updated_at||'')));$('count').textContent=s.items.length;renderList();if(select&&s.items.length){const c=s.items.find(x=>x.id===wanted)||s.items[0];await pick(c.id)}}
function renderList(){const l=$('list');l.innerHTML='';for(const c of s.items){const b=document.createElement('button');b.className='conv'+(c.id===s.id?' active':'');b.textContent=`${c.title||'Untitled'} · ${c.message_count}`;b.onclick=()=>pick(c.id);l.appendChild(b)}}
async function pick(id){s.id=id;s.conv=await api(`/api/conversations/${encodeURIComponent(id)}`);$('title').textContent=s.conv.title||'Untitled';$('subtitle').textContent=`${id} · provider: ${idv(s.conv.provider)} · model: ${idv(s.conv.model)}`;setIdent(s.conv);$('input').disabled=false;$('send').disabled=false;renderMsgs();renderList()}
function scrollMessagesBottom(){const box=$('messages');box.scrollTop=proofFinal?0:box.scrollHeight}
function settleBottomScroll(){scrollMessagesBottom();requestAnimationFrame(scrollMessagesBottom);setTimeout(scrollMessagesBottom,100);setTimeout(scrollMessagesBottom,400);setTimeout(scrollMessagesBottom,900)}
function renderMsgs(){const box=$('messages');box.innerHTML='';s.tools=new Map();s.rail=null;if(proofFinal)box.appendChild(proofDigest());for(const m of s.conv?.messages||[])box.appendChild(msg(m));settleBottomScroll()}
function msg(m){const a=document.createElement('article');a.className='message '+String(m.role||'').toLowerCase();a.innerHTML='<div class="role"></div>';a.querySelector('.role').textContent=m.role||'message';if(m.content){const d=document.createElement('div');d.textContent=proofFinal&&String(m.role).toLowerCase()==='assistant'?cleanFinal(m.content):m.content;a.appendChild(d)}for(const p of m?.metadata?.tool_parts||[])a.appendChild(tool({kind:p.tool,success:(p.state||{}).status!=='error',output:(p.state||{}).output||'',metadata:p}));return a}
function cleanFinal(t){return String(t||'').replace(/Complete all six phases before reporting\.[\s\S]*?Required exact path\s*/i,'').trim()||String(t||'')}
function toolName(p){return p.kind||p.name||p.tool||p.tool_name||p.metadata?.tool||'tool'}
function outputText(p){const n=toolName(p);const raw=String(p.output||p.error||p.result||'completed').trim();if(p.success===false)return raw.length>260?raw.slice(0,260)+'…':raw;if(!raw)return 'Completed.';const first=raw[0];if(first==='{'||first==='['){let obj=null;try{obj=JSON.parse(raw)}catch{}if(obj&&typeof obj==='object'){const files=filesFrom({metadata:obj});const keys=Object.keys(obj).filter(k=>!['output','stdout','stderr','content','data'].includes(k)).slice(0,4);if(n==='repo_info')return `Repo inspected${files.length?': '+files.join(', '):'.'} ${keys.length?'Fields: '+keys.join(', ')+'.':''}`;if(n==='file_list'||n==='file_glob')return `${label(n)} completed${files.length?': '+files.slice(0,3).join(', '):'.'}`;if(n==='file_read')return `Read file${files.length?': '+files[0]:'.'}`;if(n==='shell_command')return 'Command completed. Output is in technical details.';return `${label(n)} completed. Technical output is collapsed below.`}return `${label(n)} completed. Technical output is collapsed below.`}const cleaned=raw.replace(/\s+/g,' ').trim();return cleaned.length>220?cleaned.slice(0,220)+'…':cleaned}
function filesFrom(p){const text=JSON.stringify(p.metadata||p);const found=[...text.matchAll(/[A-Za-z0-9_./-]+\.(?:rs|md|json|toml|sh|txt|yml|yaml|py)/g)].map(x=>x[0]);return [...new Set(found)].slice(0,4)}
function tool(p){const n=toolName(p);const d=document.createElement('div');d.className='tool '+(p.success===false?'err':'ok');d.dataset.proof='opencode-tool-result-card human-tool-label';d.dataset.toolName=n;const files=filesFrom(p);d.innerHTML='<div class="tool-head"><span class="tool-title"></span><span class="badge"></span></div><div class="tool-sub"></div><div class="file-list"></div><div class="tool-result"></div><details><summary>technical details</summary><pre></pre></details>';d.querySelector('.tool-title').textContent=label(n);const badge=d.querySelector('.badge');badge.className='badge '+(p.success===false?'err':'ok');badge.textContent=p.success===false?'needs attention':'done';d.querySelector('.tool-sub').textContent=`raw tool: ${n}`;d.querySelector('.file-list').innerHTML=files.map(f=>`<span class="file-pill">${f}</span>`).join('');d.querySelector('.tool-result').textContent=outputText(p);d.querySelector('pre').textContent=JSON.stringify(p.metadata||p,null,2);return d}
function liveTool(d){let el=s.tools.get(d.id);const n=d.name||d.tool||'tool';if(!el){el=document.createElement('div');el.className='tool live';el.dataset.proof='opencode-live-toolpart providerExecuted human-tool-label';el.dataset.toolName=n;el.innerHTML='<div class="tool-head"><span class="tool-title"></span><span class="badge info">running</span></div><div class="stages"></div><div class="tool-sub"></div><details><summary>technical ToolPart lifecycle</summary><pre></pre></details>';$('messages').appendChild(el);s.tools.set(d.id,el)}el.querySelector('.tool-title').textContent=label(n);const chip=document.createElement('span');chip.className='stage';chip.textContent=String(d.stage||'event').replace(/-/g,' ');el.querySelector('.stages').appendChild(chip);el.querySelector('.tool-sub').textContent=`provider executed: ${String(!!d.providerExecuted)} · call ${d.id}`;el.querySelector('pre').textContent=JSON.stringify(d,null,2);scrollMessagesBottom();return el}
function rail(){if(s.rail)return s.rail;const r=document.createElement('div');r.className='rail';r.dataset.proof='opencode-eventv2bridge-stream';r.innerHTML='<strong>Activity receipts</strong><div></div>';$('messages').appendChild(r);s.rail=r;return r}
function appendRail(kind,d){const row=document.createElement('div');const file=d.path||d.file||d.filepath||d.target||'';row.textContent=`${String(kind).replace(/-/g,' ')}${file?': '+file:''}`;row.title=JSON.stringify(d).slice(0,500);rail().querySelector('div').appendChild(row);scrollMessagesBottom()}
function appendUser(t){const a=document.createElement('article');a.className='message user';a.innerHTML='<div class="role">user</div>';const d=document.createElement('div');d.textContent=t;a.appendChild(d);$('messages').appendChild(a);scrollMessagesBottom()}
function assistant(){if(s.stream)return s.stream;const a=document.createElement('article');a.className='message assistant';a.innerHTML='<div class="role">assistant live answer</div><div></div>';$('messages').appendChild(a);s.stream=a.querySelector('div:last-child');scrollMessagesBottom();return s.stream}
function proofDigest(){const messages=s.conv?.messages||[];const tools=[];let final='';for(const m of messages){if(String(m.role).toLowerCase()==='assistant'&&m.content)final=m.content;for(const p of m?.metadata?.tool_parts||[])tools.push(p)}const files=[...new Set(tools.flatMap(p=>filesFrom({metadata:p})))].slice(0,8);const names=[...new Set(tools.map(p=>p.tool).filter(Boolean))];const card=document.createElement('section');card.className='proof-card';card.dataset.proof='proof-digest-visible final-answer-visible human-tool-label';card.innerHTML=`<h2>Run proof summary</h2><div class="muted">Completed WebUI run with visible model route, readable action cards, and final answer below.</div><div class="proof-grid"><div class="metric"><b>${idv(s.conv?.provider)}</b><span>provider</span></div><div class="metric"><b>${idv(s.conv?.model)}</b><span>model</span></div><div class="metric"><b>${tools.length}</b><span>tool results</span></div><div class="metric"><b>${names.map(label).slice(0,3).join(', ')||'actions recorded'}</b><span>actions used</span></div></div><div><strong>Files touched or inspected</strong><div class="file-list">${files.map(f=>`<span class="file-pill">${f}</span>`).join('')||'<span class="mini">No file path metadata found</span>'}</div></div><h3>Final answer</h3><div class="final-answer"></div>`;card.querySelector('.final-answer').textContent=cleanFinal(final)||'Final answer not recorded yet.';return card}
function ev(name,d){if(name==='text-delta'){assistant().textContent+=d.text||d.delta||'';scrollMessagesBottom()}else if(name==='tool-lifecycle'||name==='tool-input-start'||name==='tool-input-delta'||name==='tool-input-end'||name==='tool-call')liveTool(d);else if(name==='tool-result'||name==='tool-error'){$('messages').appendChild(tool(d));scrollMessagesBottom()}else if(name==='file-change'||name==='event-bus')appendRail(name,d);else if(name==='conversation'){s.conv=d;setIdent(d)}else if(name==='run-finish'){setIdent(s.conv,d);toast('Run finished');settleBottomScroll()}else if(name==='provider-error')toast(d.message||'provider error')}
async function read(r){const reader=r.body.getReader(),dec=new TextDecoder();let buf='';while(true){const {value,done}=await reader.read();if(done)break;buf+=dec.decode(value,{stream:true});let parts=buf.split('\n\n');buf=parts.pop();for(const part of parts){let name='message',data='';for(const line of part.split('\n')){if(line.startsWith('event:'))name=line.slice(6).trim();if(line.startsWith('data:'))data+=line.slice(5).trim()}try{ev(name,data?JSON.parse(data):{})}catch(e){toast(e.message)}}}}
async function send(){const text=$('input').value.trim();if(!text||!s.id||s.busy)return;s.busy=true;s.stream=null;s.tools=new Map();s.rail=null;$('input').value='';$('send').disabled=true;appendUser(text);const r=await fetch(`/api/conversations/${encodeURIComponent(s.id)}/chat/stream`,{method:'POST',headers:{'content-type':'application/json','accept':'text/event-stream'},body:JSON.stringify({message:text,max_rounds:10})});await read(r);await pick(s.id);await load(false);s.busy=false;$('send').disabled=false}
async function create(){const c=await api('/api/conversations',{method:'POST',body:JSON.stringify({title:'live browser model proof'})});await load(false);await pick(c.id)}
$('new').onclick=()=>create().catch(e=>toast(e.message));$('send').onclick=()=>send().catch(e=>{s.busy=false;toast(e.message)});$('input').addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();send().catch(x=>toast(x.message))}});loadCatalog().catch(e=>toast(e.message));load(true).catch(e=>toast(e.message));
</script>
</body>
</html>"##;
